    el = document.getElementById('dashHashtagTotal'); if (el) el.textContent = hashtagData.length;
    el = document.getElementById('dashFunfactTotal'); if (el) el.textContent = funfactData.length;
    el = document.getElementById('dashScheduleTotal'); if (el) el.textContent = scheduleData.length;
    el = document.getElementById('dashTicketTotal'); if (el) el.textContent = ticketData.length;
