    el = document.getElementById('dashGalRalvandraTotal'); if (el) el.textContent = countGalPhotos(galRalvandraData);
    el = document.getElementById('dashGaleriTotal'); if (el) el.textContent = countGalPhotos(galRalyneData) + countGalPhotos(galRalvandraData);
